INSERT INTO "BetaApplication" ("id", "fullName", "email", "company", "role", "motivation", "createdAt") VALUES ('cmima2a7i0000mm08c8l60m6f', NULL, 'sufyan.elahi@axiomworld.net', 'Axiom World (Pvt.) Ltd.', 'Director', 'A LinkedIn video you guys shared. \n\nWe''ve worked together by the way, we have been doing Odoo work for you guys. ', '2025-11-30T22:14:10.734Z') ON CONFLICT (id) DO NOTHING;

