INSERT INTO "ContactSubmission" ("id", "fullName", "email", "company", "message", "createdAt") VALUES ('cmjmss5eb0000lh0806fb5iyi', NULL, 'devam.braincrewapps@gmail.com', 'Braincrew Apps', 'Dear KnowCap Team,\n\nI would like to share some feedback regarding your product, particularly from my experience as a developer working with your platform.\n\nLack of Pause Button During Recording:\nWhen I record videos, there is no pause button, which results in clients sending over the entire video, including unnecessary sections. This makes the process less efficient for us.\n\nInaccurate Transcription:\nThe transcription feature doesn’t seem to be very accurate. I don’t quite understand the purpose of transcriptions when they don’t offer a reliable output, especially since I can’t even use them for summarizing the content.\n\nVideo Player Issues:\nWhen I pause a video and switch to another tab, then return, the video keeps loading endlessly. This forces me to rewind and try to remember the timestamp I was at, which is very time-consuming. The overall video player feels quite basic and lacks the usability improvements that would make it easier to navigate.\n\nI hope this feedback helps improve the product. Thank you for your attention to these issues.\n\nBest regards,\nDevam', '2025-12-26T11:37:52.979Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO "ContactSubmission" ("id", "fullName", "email", "company", "message", "createdAt") VALUES ('cmjd8oe5b0000pe08zw78j793', NULL, 'mohamedfaroukelmekawy@gmail.com', 'Individual', 'Hello,\nMy name is Mohamed Farouk. I am a Computer Science graduate with a strong interest in AI automation and intelligent systems. I have experience with Python, LLMs, APIs, and AI-driven workflows, and I am seeking an internship or junior AI engineer opportunity to learn and contribute to real-world AI products.\n\nPlease find my CV here:\nhttps://drive.google.com/file/d/12ldDKCC-qq3FZlGm45sS48OxxshE2bCl/view?usp=drive_link\n\nI would be happy to discuss how I can add value to Knowcap.\nThank you for your time.\n\nBest regards,\nMohamed Farouk', '2025-12-19T19:05:09.792Z') ON CONFLICT (id) DO NOTHING;

-- RecruitmentApplication data (32 records)
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjypaw3f0001pj08hkjyj6kr', 'Menna El Safty', 'mennaelsafty@aucegypt.edu', 'product-manager', 'university', NULL, NULL, NULL, NULL, 'MennaElSaftyResume.pdf', '14890/uploads/1767468822948-MennaElSaftyResume.pdf', FALSE, '2026-01-03T19:33:43.035Z', 45, 'The candidate, Mennatullah Wael El Safty, is currently an undergraduate student pursuing a Bachelor of Business Administration in Management of Information and Communication Technology with a minor in Business Entrepreneurship. They have relevant internship and work experience in marketing, ESG, business development, and digital content management, but lack direct product management experience, especially 3-5+ years. There is no evidence of experience with AI/ML products or building 0-to-1 products. The candidate demonstrates some technical skills including programming languages (C++, Python, SQL, R) and data analytics tools (Power BI, XLMiner), which indicates a technical background but not necessarily at the level of product management or AI product development. Their roles show some user-centric activities such as market research and content creation, but there is limited indication of user needs analysis or roadmap planning. Experience working with engineering teams is not explicitly mentioned. The candidate’s extracurricular leadership roles show initiative and collaboration skills but are not directly related to product management. Overall, the candidate shows potential and foundational skills but lacks the core product management experience and AI/ML exposure required for this role.', 'moderate_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjyp9uoq0000pj08gh7bia4a', 'Menna El safty', 'mennaelsafty@aucegypt.edu', 'founding-ai-engineer', 'university', NULL, NULL, NULL, NULL, 'MennaElSaftyResume.pdf', '14890/uploads/1767468774447-MennaElSaftyResume.pdf', FALSE, '2026-01-03T19:32:54.555Z', 35, 'The candidate is an undergraduate student pursuing a Bachelor of Business Administration in Management of Information and Communication Technology, with a minor in Business Entrepreneurship. Their experience includes internships and part-time roles in marketing, ESG, business development, and educational content creation, with some exposure to programming languages such as C++, Python, SQL, and R. However, the candidate lacks professional software engineering experience, especially the 5-7+ years required. There is no evidence of hands-on experience with Retrieval-Augmented Generation (RAG) pipelines, LLM workflows, or complex system architecture. The resume does not demonstrate expertise in chunking, embedding, hybrid search strategies, or cloud-based system shipping. Additionally, there is no mention of experience with LangChain, vector databases, reranking pipelines, or multimodal AI models. While the candidate shows strong academic performance and some programming knowledge, they do not meet the technical depth, experience, or startup ownership mindset required for a Founding AI Engineer role with a path to CTO.', 'weak_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjoipkl00000mv08tq6fn00r', 'Nour Ahmed ', '01026710714n@gmail.com', 'head-of-growth', 'linkedin', NULL, NULL, 'Ai sales automation \nGTM engineering ', NULL, 'Nour Ahmed cv.docx', '14890/uploads/1766853088757-Nour_Ahmed_cv.docx', FALSE, '2025-12-27T16:31:28.884Z', 68, 'Nour Ahmed demonstrates solid experience in AI-driven business development and sales, particularly in B2B lead generation and early-stage market expansion across Gulf and European markets. The candidate has hands-on experience designing AI-powered lead generation systems and automating sales pipelines, which aligns well with the role''s focus on growth and revenue. Nour shows proficiency in CRM workflow automation, sales funnel optimization, and generating qualified leads, all critical for a Head of Growth role. However, the candidate''s total professional experience appears limited (approximately 2-3 years), which is below the preferred 5-7+ years of growth or revenue experience. While Nour has experience with AI products and some marketing analytics, there is limited evidence of owning end-to-end growth strategy or leading growth experiments at scale. The educational background is not directly related to business or marketing, and the role of Head of Growth typically demands deeper strategic leadership and execution experience in B2B SaaS or agency sales environments. Overall, Nour is a promising candidate with relevant technical skills and a growth mindset but may require more senior-level experience to fully meet the role''s expectations.', 'good_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjixm0n40000uw083bnnsi6o', 'Ahmed Mahdi', 'agelmahdi@gmail.com', 'founding-ai-engineer', 'friend', 'https://www.linkedin.com/in/agelmahdi', 'https://github.com/agelmahdi?tab=repositories', NULL, NULL, 'Ahmed_Mahdi_AI_Engineer_Resume.pdf', '14890/uploads/1766515320188-Ahmed_Mahdi_AI_Engineer_Resume.pdf', FALSE, '2025-12-23T18:42:00.257Z', 88, 'Ahmed Mahdi is a strong candidate for the Founding AI Engineer role with a clear focus on AI/ML software engineering, system architecture, and generative AI techniques. He has over 4 years of professional software engineering experience (Aug 2020 - present) and is currently a Lead Software Engineer and AI/ML Engineer, indicating rapid career progression and leadership. He demonstrates deep hands-on experience with RAG pipelines, having designed systems using LangChain, LlamaIndex, Milvus, and FAISS, which aligns well with the requirement for expertise in chunking, embedding, and hybrid search strategies. His proficiency in Python and the ML ecosystem (PyTorch, TensorFlow, Keras, Scikit-learn) is strong, and he has cloud experience with AWS services (SageMaker, Lambda, EC2, S3), Docker, and CI/CD, fulfilling the need for shipping complex systems in cloud environments. Ahmed also shows strong architectural and systems thinking through his ownership of AI initiatives, scalable production-grade architecture design, and deployment strategies that reduce costs and hallucination rates. His experience with LLM workflows, fine-tuning (LoRA/QLORA), prompt engineering (CoT/ToT), and agentic AI workflows matches the requirement for LLM orchestration expertise. While he has experience with LangChain and LlamaIndex, there is no explicit mention of LangGraph or vector databases like Pinecone or Weaviate, nor multimodal AI models or reranking pipelines, which are nice-to-haves but not critical. Overall, Ahmed demonstrates a pragmatic, high-ownership mindset suitable for a startup environment and a path to CTO role.', 'strong_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjh3hko50000o708gvh039s0', 'Ghada Essam', 'gabdalraheem@gmail.com', 'product-manager', 'linkedin', 'https://www.linkedin.com/in/ghada-e-abdalraheem-19175918/', NULL, 'Several ai automations and end-to-end solutions for capital market research and ratings, corporate financial assessments and ESG Ratings, Financial advisor chatbot, Quantitative and Qualitative report generation', 'After 20 years in product management and several recent years in AI, I’m at a stage where I want to build alongside founders with ownership and long-term impact. As an Economist by the heart, Strategist by choice I’ve always been driven by development, efficiency, and optimization, my guiding principle is AI for good—i am excited to apply it to scale, fasten, improve processes and re-allocate the human brains and effort to the more superior cognitive and sentient tasks that machines cant do. I am excited to apply my experience to not use ai where it shouldn’t be. whether its a revolution or a hype. Its here to stay, and the wisdom is to apply it masterfully.', 'Ghada abdelraheem - Head of Innovation - Fintech.pdf', '14890/uploads/1766404258196-Ghada_abdelraheem_-_Head_of_Innovation_-_Fintech.pdf', FALSE, '2025-12-22T11:50:58.277Z', 85, 'The candidate, Ghada Abdelraheem, has over 15 years of product management experience, including 5+ years in roles directly related to product development and innovation, which meets and exceeds the 3-5+ years requirement. She has a strong technical background demonstrated by managing AI & ML teams and projects involving NLP, RAG, and Computer Vision, aligning well with the AI/ML product experience requirement. Her current role as Head of Innovation involves leading product development cycles from ideation to delivery, indicating strong user-centric product thinking and experience working closely with engineering teams. The resume highlights her involvement in roadmap planning and product strategy, as well as developing new solution blueprints and prototypes, which aligns with the must-have criteria of building 0-to-1 products and understanding user needs. The candidate''s MBA in Strategic Management and Bachelor of Economics provide a strategic and analytical foundation, though she does not have a formal technical or engineering degree, which is a minor gap. She has enterprise product experience in fintech and capital markets, and knowledge of RAG systems is explicitly mentioned. Her profile also emphasizes data-driven decision making and a passion for AI applied responsibly, which fits well with the role''s expectations. Overall, she is a strong fit with minor gaps in formal technical education but compensated by extensive relevant experience and leadership in AI product development.', 'strong_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjg90sy60000pi08ie3mvgyo', 'Nourhan Tantawi', 'nourhantantawi@aucegypt.edu', 'product-manager', 'university', NULL, NULL, NULL, 'I am an MICT graduate from AUC', 'NourhanTantawi_CV.pdf', '14890/uploads/1766353087243-NourhanTantawi_CV.pdf', FALSE, '2025-12-21T21:38:07.374Z', 50, 'The candidate holds a Bachelor of Business in Management of Information and Communication Technology (MICT) from AUC, which provides a relevant technical foundation. Their work experience is primarily in presales consulting and technical sales roles, involving preparation of technical and financial proposals, client engagement, and some software testing. While this shows strong client-facing and technical communication skills, there is no direct product management experience or evidence of owning product roadmaps, building 0-to-1 products, or leading product development cycles. The candidate has some exposure to AI and data science fundamentals through IBM digital credentials, but no direct AI/ML product experience or involvement with RAG systems is mentioned. User-centric product thinking and data-driven decision making are not explicitly demonstrated. The candidate has experience working with technical teams and preparing technical documents, which suggests some ability to collaborate with engineering teams. Overall, the candidate shows potential but lacks core product management experience and specific skills required for this role.', 'moderate_fit', 'Interviewed', NULL, NULL, '', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjd7mdg90001pm084g45v091', 'saleh hesham', 'salehhesham@aucegypt.edu', 'product-manager', 'university', 'https://www.linkedin.com/in/saleh-hesham/', NULL, 'Developed a sales and promotions platform to streamline interdepartmental communication and ensure all tasks are efficiently tracked with defined SLAs.', NULL, 'Saleh Hesham CV.pdf', '14890/uploads/1766169335856-Saleh_Hesham_CV.pdf', FALSE, '2025-12-19T18:35:35.961Z', 68, 'The candidate, Saleh Hesham Aboalatta, has a strong technical background with proficiency in multiple programming languages (Python, C++, Java, Flutter) and experience using Power Platform tools (Power Automate, Power BI, Power Apps). He has demonstrated experience in building automation and digital platforms, including a sales and promotions platform that streamlined interdepartmental communication with defined SLAs, which aligns well with product management responsibilities. His thesis project involved designing a customized Inventory & Asset Management System, showing capability in 0-to-1 product development and user interface design with stakeholder collaboration, indicating user-centric product thinking. He has experience working with engineering teams, agile methodologies, and project management tools like Jira and Slack, supporting his ability to work cross-functionally. \n\nHowever, the candidate has less than 1 year of full-time professional experience (started August 2024), which is below the 3-5+ years product management experience requirement. His AI/ML exposure is limited to academic projects and some AI-powered solutions but lacks clear product management ownership of AI/ML products. There is no explicit mention of roadmap planning or enterprise product experience. Knowledge of RAG systems is not indicated. Overall, while technically strong and demonstrating relevant project experience, the candidate is early in his career and would benefit from more direct product management experience and leadership in AI product contexts.', 'good_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjd7kkj40000pm089l7mgaye', 'saleh hesham', 'salehhesham@aucegypt.edu', 'executive-assistant', 'university', 'https://www.linkedin.com/in/saleh-hesham/', NULL, 'Developed a sales and promotions platform to streamline interdepartmental communication and ensure all tasks are efficiently tracked with defined SLAs.', NULL, 'Saleh Hesham CV.pdf', '14890/uploads/1766169251713-Saleh_Hesham_CV.pdf', FALSE, '2025-12-19T18:34:11.824Z', 55, 'The candidate has strong technical and project experience, particularly in automation, data analysis, and software development, but limited direct experience as an executive assistant. There is no explicit mention of supporting C-level executives, calendar or meeting management, or travel coordination. The resume highlights strong organizational skills through project management and leadership roles, as well as good communication demonstrated by stakeholder engagement and presentations. The candidate shows a proactive problem-solving mindset via multiple automation projects and workflow improvements. However, professional communication skills in an executive support context and handling confidential information are not clearly evidenced. The candidate has some event planning and project coordination experience through leadership roles and university activities, and familiarity with productivity tools is evident from extensive use of Microsoft Power Platform and project management software. Overall, the candidate is a technically skilled professional with some transferable skills but lacks core executive assistant experience and direct exposure to key must-have responsibilities.', 'moderate_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjbd4gfj0001qo089hv2fz1o', 'Abdelrahman Hassan', 'abdohassan7001@gmail.com', 'founding-ai-engineer', 'linkedin', 'https://www.linkedin.com/in/abdelrahman-hassan-36836a199?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app', 'https://github.com/abdelrahman70700', 'Published a paper in IEEE journal and all details in my CV ', NULL, 'Abdelrahman_CV_latest-1.pdf', '14890/uploads/1766057645287-Abdelrahman_CV_latest-1.pdf', FALSE, '2025-12-18T11:34:05.360Z', 68, 'The candidate has approximately 2+ years of professional experience as a Machine Learning Engineer, which is below the 5-7+ years required for this founding AI engineer role. They demonstrate strong proficiency in Python and the ML ecosystem, including TensorFlow, Keras, and NLP frameworks. They have hands-on experience building and deploying Retrieval-Augmented Generation (RAG) chatbots, which aligns well with the key requirement of RAG pipeline experience. The candidate also shows solid skills in data analytics, algorithm development, and user-friendly interface integration, indicating good systems thinking and pragmatic problem-solving. However, there is no explicit mention of shipping complex systems in cloud environments or deep architectural experience, which are critical for a founding role with CTO path. The resume lacks evidence of expertise in chunking, embedding, hybrid search strategies, or orchestration of LLM workflows, which are must-haves. There is no mention of LangChain, LangGraph, vector databases, or reranking pipelines, which are nice-to-haves. The candidate’s academic achievements and IEEE publication on a novel deep-learning pipeline demonstrate strong technical capability and research acumen but do not fully compensate for the experience gap or missing cloud and architectural expertise. Overall, the candidate is a good fit for a mid-level ML engineer role with some exposure to RAG and NLP but falls short of the seniority and breadth required for a founding AI engineer position.', 'good_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmjbd1mps0000qo08gk8a60hu', 'Amr Sherif Abou Ghaly', 'amraboughali@aucegypt.edu', 'product-manager', 'friend', NULL, NULL, NULL, NULL, 'Amr Sherif Abou Ghaly - Resume 2025.pdf', '14890/uploads/1766057513440-Amr_Sherif_Abou_Ghaly_-_Resume_2025.pdf', FALSE, '2025-12-18T11:31:53.537Z', 55, 'The candidate has a background primarily in finance, real estate investment advisory, and digital marketing, with recent completion of product management courses. They have no direct product management work experience, let alone 3-5 years, but have gained foundational knowledge through Udacity and Mind the Product certifications completed in 2025. The candidate demonstrates strong data analysis skills, user and market research experience, and the ability to translate insights into presentations and strategic recommendations, which aligns with user-centric and data-driven decision making. However, there is no evidence of hands-on experience building 0-to-1 products, working directly with engineering teams, or roadmap planning. The technical skills listed are mostly related to MS Office tools and analytics platforms, with no mention of AI/ML product experience or engineering background. There is also no indication of experience with AI products, RAG systems, or enterprise product environments. Overall, the candidate shows potential and foundational knowledge but lacks the practical product management experience and technical background required for this role.', 'moderate_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmja70dtv0001ll08rbrailfp', 'Ahmed ELshahawy', 'ahmedelshahawy078@gmail.com', 'founding-ai-engineer', 'friend', NULL, 'https://github.com/A-Elshahawy/', 'I built FlexiTransformer, a modular Transformer framework that allows experimenting with different architectures (encoder/decoder, BERT-like or GPT-like) and swapping positional encoding methods (standard, ALiBi, etc.) to study their impact on training and performance, making it easier to prototype and debug custom Transformer models.\n', NULL, 'Ahmed-Elshahawy-Resume.pdf', '14890/uploads/1765986911398-Ahmed-Elshahawy-Resume.pdf', FALSE, '2025-12-17T15:55:11.490Z', 72, 'The candidate is a driven AI and machine learning engineer with strong hands-on experience in Python, PyTorch, and ML workflows, including fine-tuning large language models (LLMs) and building RAG-based document question answering systems. They have demonstrated expertise in chunking, embedding, and vector databases (Pinecone), and have worked on parameter-efficient fine-tuning techniques like LoRA and QLoRA, which aligns well with the LLM workflows and orchestration requirement. Their experience includes building scalable NLP pipelines and MLOps workflows, indicating some systems thinking and deployment experience. However, the candidate has only about 1-2 years of professional experience (2023-present as freelancer and 2025-present at Tuba, which seems inconsistent with current date but assuming recent experience), which is below the 5-7+ years required. There is no explicit mention of shipping complex systems in cloud environments or deep architectural leadership. While they have used LangChain and vector databases, there is no evidence of experience with reranking pipelines or multimodal AI models. The portfolio includes a modular Transformer framework (FlexiTransformer) which shows strong research and prototyping skills but less evidence of pragmatic startup ownership or large-scale system shipping. Overall, the candidate shows strong technical skills and relevant ML experience but lacks the depth of professional experience and proven track record in complex system delivery and startup leadership expected for a founding AI engineer role.', 'good_fit', 'Interviewed', NULL, NULL, 'technical knowledge perfect', 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj9xq8bv0000ll08f5pgu663', 'Mohamed Ibrahim Mohamed Ibrahim Behery', 'mohamed.i.behery@proton.me', 'founding-ai-engineer', 'job_board', 'https://www.linkedin.com/in/mohamed-ibrahim-behery', 'https://github.com/m-behery', 'I. TSP-clustering for Video Frame Segmentation: Temporally Stable super-Pixel (TSP) clustering of video frames using an SSN architecture developed from scratch, in PyTorch, for spatio-temporal dependency, and reuses RAFT for computing optical flows in a low latency GPU-computation setting for fast inference.\n		\nII. Multilingual E-commerce RAG System: A RAG pipeline enabling cross-lingual product search and recommendation. System generates English product embeddings, performs semantic retrieval on translated queries, and delivers recommendations in user''s native language/dialect. Achieved language-agnostic search across multilingual catalogs without requiring translated product descriptions.', NULL, 'mohamed-behery.pdf', '14890/uploads/1765971321132-mohamed-behery.pdf', FALSE, '2025-12-17T11:35:21.259Z', 82, 'The candidate, Mohamed Behery, demonstrates over 10 years of professional experience in R&D and software development, which exceeds the 5-7+ years requirement. He has strong proficiency in Python and ML ecosystems, with expertise in PyTorch, Scikit-image, and Pandas. His experience includes architecting low-latency ML inference pipelines and mentoring technical teams, indicating strong architectural and systems thinking. Notably, he has developed a Multilingual E-commerce RAG System that aligns directly with the requirement for hands-on experience with RAG pipelines, including embedding generation, semantic retrieval, and cross-lingual recommendations, showcasing deep knowledge of chunking, embedding, and hybrid search strategies. He also has experience optimizing LLM services, demonstrating familiarity with LLM workflows and orchestration. \n\nWhile the resume does not explicitly mention cloud environment deployment or shipping complex systems in cloud, his work on GPU-based image segmentation and low-latency ML systems suggests relevant experience with scalable, production-grade systems. The candidate shows a pragmatic, high-ownership mindset through freelance research contributions and mentoring roles, fitting a startup environment well. \n\nRegarding nice-to-haves, there is no explicit mention of LangChain, LangGraph, or vector databases like Pinecone or Weaviate, nor reranking pipelines. However, his work on multimodal projects like video frame segmentation and speech signals indicates some exposure to multimodal AI models. \n\nOverall, Mohamed is a strong candidate with direct experience in key areas, especially RAG pipelines and ML system architecture, making him a strong fit for the Founding AI Engineer role with a path to CTO.', 'strong_fit', 'Interviewed', NULL, NULL, 'Really great theoratical work but have not developed production ready software we need a major coding test to make sure that he is good but has really good leadership because he taught students', 4) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj9ber1t0000qa0856f5myzf', 'Yasmin Ashraf Abdelrehim Tawfik Weshahi', 'yasmineweshahy@aucegypt.edu', 'product-manager', 'friend', 'https://www.linkedin.com/in/yasmin-weshahi-a3b28126b/', 'https://www.canva.com/design/DAG7tQ1CQlQ/U5xkYC1WY3nLpq949VLaXg/view?utm_content=DAG7tQ1CQlQ&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h7521775303', 'Used AI to help me design and develop websites for my freelance clients (Workout Studio Website and Autoparts e-commerece website) which are soon to be deployed live. ', NULL, 'YasminWeshahi_CV__2025.pdf', '14890/uploads/1765933833988-YasminWeshahi_CV__2025.pdf', FALSE, '2025-12-17T01:10:34.098Z', 68, 'The candidate, Yasmin Weshahi, is currently a Bachelor student expected to graduate in Fall 2025, with a focus on Management of Information and Communication Technology. She has internship experience related to product management and design, including roles at Vodafone Intelligent Solutions and Vodafone Business Unit, where she gained exposure to product lifecycle, UI/UX design, Agile methodologies, and backlog management. She also has freelance experience as a UI/UX designer and front-end developer, building websites with modern frameworks and incorporating AI tools to assist in design and development. Her thesis project involved designing an end-to-end digital procurement system with strong technical deliverables such as ERD/DFD documentation and database/dashboard development, demonstrating technical and data-driven skills.\n\nHowever, she lacks the 3-5+ years of product management experience required for the role, as her experience is primarily internship and freelance work during her studies. There is no explicit mention of AI/ML product experience beyond using AI tools for website design, nor is there evidence of enterprise product experience or knowledge of RAG systems. She shows user-centric thinking through UI/UX work and product workshops, and has worked with engineering teams in internships and freelance projects. Roadmap planning experience is implied but not strongly detailed. Her technical skills include programming languages and tools relevant to product and development collaboration.\n\nOverall, Yasmin demonstrates strong potential with relevant internships, technical skills, and user-centric product exposure but lacks the depth of experience and specific AI/ML product management background required for this senior role.', 'good_fit', 'Interviewed', NULL, NULL, 'She would be really good for Smetools and Ariika website overhaul.', 4) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8wflry0005od082gy1j7ss', 'Ammar ahmed thabet', 'ammarahmedthabet@gmail.com', 'founding-ai-engineer', 'linkedin', 'https://www.linkedin.com/in/ammar-thabett/', 'https://github.com/ammarthabet7', NULL, NULL, 'Ammar_Thabet.pdf', '14890/uploads/1765908679444-Ammar_Thabet.pdf', FALSE, '2025-12-16T18:11:19.678Z', 68, 'The candidate, Ammar Ahmed Thabet, is a recent Computer Science graduate with just over a year of professional experience in AI and machine learning, including part-time and volunteering roles. He demonstrates strong technical skills in Python, ML frameworks (TensorFlow, PyTorch), and cloud technologies (AWS EC2, RDS), and has hands-on experience architecting and deploying complex AI systems, including a hybrid retrieval system combining schema-grounded SQL generation with RAG (Retrieval-Augmented Generation) pipelines. This aligns well with the requirement for experience with RAG pipelines and LLM workflows. He also shows strong architectural thinking through projects like the Retail Analytics Copilot, which involves multi-source data fusion, error correction, and secure on-premise deployment. \n\nHowever, the candidate lacks the 5-7+ years of professional software engineering experience required for a founding AI engineer role, having only about one year of part-time experience and volunteering. While he has demonstrated leadership and ownership in AI projects and teams, his experience is more academic and project-based rather than extensive industry-level software engineering. There is no explicit mention of experience with LangChain, LangGraph (though he used LangGraph in a project), or vector databases like Pinecone or Weaviate, though he has worked with vector-based document retrieval. Multimodal AI experience and reranking pipelines are not evident. \n\nOverall, the candidate shows strong potential, technical proficiency, and relevant project experience, but falls short on years of professional experience and some specific tooling and systems expertise expected at a founding engineer level in a startup environment.', 'good_fit', 'Interviewed', NULL, NULL, 'an intern or a juniior at best\nBut potentianlly a very good intern or junior', 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8v0ikd0004od08hr1kq9mv', 'Ahmed Ehab ', 'aahmedehab0@gmail.com', 'founding-ai-engineer', 'linkedin', 'https://www.linkedin.com/in/aahmedehab0', 'https://github.com/aahmedehab0', 'Built a bilingual (AR/EN) query agent using RAG pipelines and LangChain/LangGraph for freelance projects.  \nImplemented intelligent routing between RAG and SQL queries.  \nDeployed small AI systems on AWS with CI/CD using GitHub Actions and Docker.', 'I am a junior Machine Learning Engineer with some practical experience in RAG pipelines and NLP systems.  \nI am eager to contribute, learn quickly, and grow my skills in AI/ML.', 'AhmadEhabCV.pdf', '14890/uploads/1765906295987-AhmadEhabCV.pdf', FALSE, '2025-12-16T17:31:36.061Z', 62, 'The candidate is an entry-level Machine Learning Engineer with about 1 year of freelance experience focused on ML/DL models, RAG pipelines, and NLP systems. They demonstrate hands-on skills in building and deploying small-scale AI solutions, including RAG pipelines with chunking, embeddings, and metadata search, as well as orchestration using Celery and Flower. They have experience deploying systems on AWS with CI/CD pipelines and Docker, which aligns with the cloud deployment requirement. The candidate shows familiarity with LangChain, LangGraph, DSPy, vector databases (Qdrant, PGVector), and LLM workflows. However, they lack the 5-7+ years of professional software engineering experience required for a founding AI engineer role. Their architectural and systems thinking skills appear limited to small-scale freelance projects rather than complex, large-scale systems. While proficient in Python and the ML ecosystem, their experience with hybrid search strategies, reranking pipelines, and deep understanding of trade-offs between models is not strongly evidenced. The candidate has a pragmatic mindset and eagerness to learn but is still at a junior level, making them a moderate fit rather than a strong or exceptional candidate for this senior startup leadership role.', 'moderate_fit', 'Interviewed', NULL, NULL, 'could potentially work as a junior but not a founding engineer', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8sg6fo0003od0898mfnfie', 'Adam  Tarek', 'adamtarek03@yahoo.com', 'product-manager', 'university', NULL, NULL, 'N8N AI agent to automate lead generation and qualification ', NULL, 'Adam Tareks Resume.pdf', '14890/uploads/1765901987888-Adam_Tareks_Resume.pdf', FALSE, '2025-12-16T16:19:47.988Z', 68, 'The candidate is a recent graduate with internship and project experience relevant to product management but lacks the 3-5+ years of direct product management experience required. They have a strong technical foundation through their Management of Information and Communication Technology degree and hands-on experience with enterprise software like SAP S/4HANA and Oracle Fusion ERP. The candidate has worked on AI-related projects, notably the lead automation AI agent workflows using n8n, which aligns with the AI/ML product experience requirement. Their academic projects demonstrate user-centric product thinking, including designing UX/UI features and building a 0-to-1 sales and inventory management system prototype, showing capability in building products from scratch and understanding user needs. They also have experience collaborating with cross-functional teams, including engineering, and using project management tools like Jira, indicating an ability to work with engineering teams. However, there is limited explicit evidence of roadmap planning experience or enterprise product ownership. The candidate’s data-driven decision-making skills are supported by their use of Power BI, Excel data mining, and analytics in projects. They have a technical degree but no direct mention of knowledge of RAG systems or extensive enterprise product management experience. Overall, the candidate is a strong early-career product management prospect with relevant technical and AI exposure but lacks seniority and some product management-specific experience.', 'good_fit', 'Link Sent', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8qsext0002od08c2650jwe', 'veronica Milad Naeem', 'vera23@aucegypt.edu', 'qa-specialist', 'linkedin', NULL, NULL, NULL, NULL, 'Veronica Naeem-  Final Resume copy.pdf', '14890/uploads/1765899199545-Veronica_Naeem-__Final_Resume_copy.pdf', FALSE, '2025-12-16T15:33:19.649Z', 45, 'The candidate, Veronica Milad Naeem, is a recent graduate with a Bachelor of Business Administration in Management of Information and Communication Technology, expected to graduate in June 2025. She has internship experience in data analysis and sales/management but lacks direct QA or testing experience, especially in AI/ML systems. Her data analysis internship involved data cleaning, validation, SQL, Excel automation, and Power BI dashboards, which demonstrate analytical skills and some automation but not specifically test automation or AI system testing. There is no evidence of experience with AI/ML testing, regression testing, quality frameworks, or familiarity with LLM testing or hallucination detection. She has strong attention to detail and an analytical mindset as shown in her academic projects and internships. However, her technical skills do not include Python or automation tools relevant to QA roles, nor observability tools. Overall, she shows potential for analytical roles but lacks the specialized QA and AI testing experience required for this position.', 'moderate_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8oy4ay0001od08uabkl2p3', 'Youssef Khorshed', 'youssefk.khorshed@gmail.com', 'head-of-growth', 'university', 'https://www.linkedin.com/in/youssef-k-828332216?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=ios_app', NULL, 'Marketing automations to turn cold leads into SQL ', NULL, 'Youssef Khorshed - CV 1.pdf', '14890/uploads/1765896106484-Youssef_Khorshed_-_CV_1.pdf', FALSE, '2025-12-16T14:41:46.571Z', 72, 'The candidate, Youssef Khorshed, has a solid background in product development and GTM strategy within the CPaaS and digital marketing space, with about 5+ years of relevant experience including freelance work since 2018 and formal roles since 2021. He has demonstrated success in demand generation, notably generating 200+ MQLs monthly with a 40% conversion rate and 6:1 ROI, which aligns well with building demand generation engines and qualified lead generation. His experience includes strong use of marketing analytics tools (HubSpot, Google Analytics 4, SEMrush, Power BI, SQL) and data-driven GTM strategies, fulfilling the analytical and funnel optimization requirements. He has also led multiple product launches and competitive intelligence efforts improving win rates by 20%, showing strategic ownership and execution capability. However, his direct experience with B2B SaaS or agency sales is implied but not explicitly detailed, and his total professional experience in growth/revenue roles is slightly below the preferred 5-7+ years in a continuous capacity. The AI/ML product marketing experience is present through his AI Voice SDR Agent project, which is a plus. Content marketing and partner/referral program experience are less emphasized or unclear. Overall, he shows strong potential but with some gaps in explicit B2B SaaS sales and longer continuous growth leadership experience.', 'good_fit', 'Interviewed', NULL, NULL, 'Really good Experience \nDownsaide 200k EGP contract in dubai \ni might have to pay 100k EGP in salaries \nI will try to pay less with a guaranteed contract', 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8oehwd0000od08kl6dj09v', 'Abdalla Hesham Elragal', 'abdalla.elragal@aucegypt.edu', 'product-manager', 'other', 'https://www.linkedin.com/in/abdallaelragal/', NULL, NULL, NULL, 'Abdalla Elragal - Resume (1).pdf', '14890/uploads/1765895190860-Abdalla_Elragal_-_Resume__1_.pdf', FALSE, '2025-12-16T14:26:31.069Z', 75, 'The candidate has approximately 1.5 years of direct product management experience at Partment, progressing from Business Operations Analyst to Product Operations Analyst and currently Associate Product Operations Manager. They have led product strategy, roadmap definition, backlog management, and sprint planning for multiple products, demonstrating experience with roadmap planning and working closely with engineering, business, and marketing teams. The candidate shows strong data-driven decision making through building product health dashboards and enabling data-driven media buying. They have a technical background with a B.A. in Management of Information and Communication Technology and skills in SQL, Python, C++, and Swift, which supports a strong technical foundation. However, there is no explicit mention of AI/ML product experience or working with AI products, nor any reference to RAG systems or enterprise product experience. The candidate has experience launching a customer support chatbot, which may indicate some exposure to AI-driven tools but is not clearly detailed as AI/ML product management. They demonstrate user-centric thinking through customer support improvements and performance evaluation systems. Overall, the candidate meets most key requirements but lacks explicit AI/ML product experience and 0-to-1 product building experience is not clearly stated, though they have led new product initiatives such as PartmentX and a rental program. The candidate''s technical degree is not engineering but related to ICT, which is a plus. Given these factors, the candidate is a strong fit but with some gaps in AI/ML and 0-to-1 product experience.', 'strong_fit', 'Interviewed', NULL, 'partment \nI think he is good but there are much stronger candidates like belal', '35k current salary \n55k expected \ntoo much for 2 to 3 years experience \n\npartment guy but keep on the look out', 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8n8ci10000rx08odjm9fh7', 'Hussein Gadelkarim', 'husseinashraf@aucegypt.edu', 'executive-assistant', 'friend', NULL, NULL, NULL, NULL, 'HusseinGadResume.pdf', '14890/uploads/1765893224387-HusseinGadResume.pdf', FALSE, '2025-12-16T13:53:44.521Z', 40, 'The candidate, Hussein Gadelkarim, has a strong background as a Business Analyst with experience in fintech and inventory management systems, demonstrating skills in requirements analysis, documentation, user experience optimization, and stakeholder communication. However, there is no evidence of executive assistant experience or direct support to C-level executives. The resume does not mention calendar or meeting management, travel coordination, handling confidential information, or professional communication skills specific to an executive assistant role. While the candidate shows project management and agile workflow experience, these are not explicitly aligned with project coordination or event planning typical for an executive assistant. The candidate''s technical skills and experience in a tech environment are a nice-to-have but do not compensate for the lack of core executive assistant competencies. Overall, the candidate''s profile does not meet the key requirements or must-haves for the Executive Assistant role.', 'weak_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
