INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8jem0o000irx08u47s738c', 'Yara Mohamed Omar', 'yaraomar@aucegypt.edu', 'executive-assistant', 'other', NULL, NULL, NULL, NULL, 'Yara Mohamed Omar - CV.pdf', '14890/uploads/1765886798187-Yara_Mohamed_Omar_-_CV.pdf', FALSE, '2025-12-16T12:06:38.329Z', 50, 'The candidate, Yara Mohamed Omar, is a recent university graduate with internship experience primarily in finance roles and project-based work rather than executive assistance. She has demonstrated skills in financial data analysis, project coordination, communication, and problem-solving through internships and academic projects. However, she lacks direct experience as an executive assistant, particularly in supporting C-level executives, calendar and meeting management, travel coordination, and handling confidential information. Her resume does not mention any experience with professional communication at an executive level or event planning. She does have some project coordination experience and familiarity with productivity tools like Excel, Access, Power BI, and Figma, which align with the nice-to-have criteria. Overall, while she shows potential and transferable skills, there are significant gaps in direct executive assistant experience and responsibilities.', 'moderate_fit', 'Interviewed', NULL, NULL, 'the right energy and the attidue \nNo experience', 3) ON CONFLICT (id) DO NOTHING;
