INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8j7j7m0006rx08pl1rstfq', 'Jolie Khaled ', 'jolie.iskandar@aucegypt.edu', 'product-manager', 'friend', NULL, NULL, 'I developed CRM and inventory management system with the aid of AI. ', NULL, 'Jolie Girgis''s resume.docx', '14890/uploads/1765886467954-Jolie_Girgis_s_resume.docx', FALSE, '2025-12-16T12:01:08.082Z', 55, 'Jolie Khaled is a highly motivated and academically strong candidate currently pursuing a Bachelor''s degree in Management of Information and Communication Technology, expected to graduate in 2025. She has demonstrated leadership and product-related experience through her roles as a Student Union UI/UX General Manager and UI/UX Manager for a Business Association Club, where she led design teams and developed user-centric digital platforms. Jolie also has internship experience in IT and media planning, showing exposure to technical environments and cross-functional collaboration. However, she lacks formal product management experience, especially the 3-5+ years required, and there is no clear evidence of experience in building 0-to-1 products or roadmap planning. While she mentions developing a CRM and inventory management system with AI aid, details on her role, scope, and AI/ML product experience are minimal and insufficient to confirm strong technical or AI product management skills. Her technical skills in SQL, C++, UI/UX design, and some coding are solid but do not fully meet the strong technical background expected. Data-driven decision making and enterprise product experience are not clearly demonstrated. Overall, Jolie shows promise as an early-career candidate with relevant skills and leadership potential but does not yet meet the core experience and technical depth required for this Product Manager role.', 'moderate_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8j2mtt0005rx08i5w8sref', 'Jolie Khaled ', 'jolie.iskandar@aucegypt.edu', 'head-of-growth', 'friend', NULL, NULL, 'I developed CRM and inventory management system with the aid of AI. ', NULL, 'Jolie Girgis''s resume.docx', '14890/uploads/1765886239385-Jolie_Girgis_s_resume.docx', FALSE, '2025-12-16T11:57:19.489Z', 42, 'Jolie Khaled is a highly motivated and academically strong candidate with a solid foundation in information and communication technology, UI/UX design, and some marketing internship experience. However, she lacks the required 5-7+ years of growth or revenue experience, and there is no evidence of a proven track record in building demand generation engines or owning growth strategy and execution. Her experience is primarily academic and internship-based, with roles focused on UI/UX management, media planning internships, and IT-related tasks rather than direct growth or revenue generation. While she has some exposure to media buying and campaign optimization, this experience is limited in duration and scope, and there is no clear indication of B2B SaaS or agency sales experience. She demonstrates strong analytical skills and familiarity with marketing analytics tools, but not at the level expected for a Head of Growth role. The AI project mentioned is minimal and does not reflect direct AI/ML product marketing experience or growth experiments. Overall, Jolie shows potential but currently does not meet the seniority or depth of experience required for this leadership growth position.', 'weak_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
