INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj8hyqst0000rx089mkqqwim', 'Maged Fam', 'magedfam@aucegypt.edu', 'product-manager', 'university', 'https://www.linkedin.com/in/maged-fam/', NULL, 'n8n automation in my thesis project', NULL, 'Maged_Fam_Resume (1).pdf', '14890/uploads/1765884378205-Maged_Fam_Resume__1_.pdf', FALSE, '2025-12-16T11:26:18.413Z', 55, 'The candidate, Maged Ramy Fam, is a current undergraduate student pursuing a B.A. in Business Administration with a focus on Management of Information and Communication Technology, expected to graduate in Fall 2025. He has internship experience related to data analysis, project management, and business analysis, including work with Python, SQL, and dashboard automation. He has exposure to AI-related topics through a Cisco internship covering AI, IoT, and cybersecurity, and has technical skills in programming and data visualization tools. However, he lacks the 3-5+ years of product management experience required for the role and does not demonstrate direct experience building 0-to-1 products or formal roadmap planning. His experience with user-centric product thinking and data-driven decision making is limited to internship contributions rather than full ownership. There is no explicit mention of AI/ML product experience or working with engineering teams in a product management capacity. The candidate’s technical background is moderate but not engineering or computer science based. The AI project mentioned (n8n automation in thesis) suggests some technical initiative but is not detailed here. Overall, he shows potential and relevant foundational skills but significant gaps remain for this senior product manager role.', 'moderate_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj739y3c0001pb085rr6r739', 'Fatema ehab ahmed mohamex', 'fatemaehab22@gmail.com', 'qa-specialist', 'linkedin', NULL, NULL, NULL, NULL, 'Fatema ehab cv.pdf', '14890/uploads/1765799240584-Fatema_ehab_cv.pdf', FALSE, '2025-12-15T11:47:20.645Z', 68, 'The candidate is a Junior Odoo ERP Developer and Software Tester with foundational knowledge in testing methodologies and ISTQB principles. They have hands-on experience writing test cases, performing API testing, and ensuring software quality. Their background includes AI and machine learning projects, such as NLP-based text summarization and an AI-based autism diagnosis app, indicating exposure to AI systems. They possess Python skills and some experience with AI/ML development, which aligns with the role''s AI testing requirements. However, the candidate has less than a year of professional experience (internships in 2023 and 2024) and does not demonstrate 3-5+ years of QA/testing experience. There is no explicit mention of test automation experience, regression testing, or detailed quality frameworks beyond ISTQB foundation. The resume lacks evidence of experience with LLM testing, hallucination detection, or observability tools. Overall, the candidate shows promise in AI and testing but has limited depth and duration of QA experience required for this specialist role.', 'good_fit', 'Interviewed', NULL, NULL, 'Perfect for a paid internship of QA testing \nShe has experience testing in odoo and she wants to gain testing in saas', 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj729svu0000pb08k9r0meak', 'Belal Bahr', 'belaltbahr@gmail.com', 'product-manager', 'linkedin', 'https://www.linkedin.com/in/belalbahr/', 'https://github.com/BelalBahr', 'Led a team of 23 engineers to build an autonomous driving car.\nTook an undocumented codebase of an erp system and built a state of the art documentation to everything.', NULL, 'Belal Bahr - Resume.pdf', '14890/uploads/1765797554151-Belal_Bahr_-_Resume.pdf', FALSE, '2025-12-15T11:19:14.298Z', 85, 'The candidate, Belal Bahr, has approximately 3 years of product management experience, primarily in technical and AI-related domains, which aligns well with the 3-5+ years requirement. He currently leads product and engineering delivery at Scalicx, managing a complex RFID-enabled automation suite, demonstrating strong technical background and experience with enterprise products. His MSc in Mechatronics & Robotics and engineering roles provide a solid technical foundation. He has led AI projects, including an autonomous driving system with a team of 23 engineers, showing experience with AI/ML products and user-centric product thinking. The candidate has experience working closely with engineering teams, leading roadmap planning, and driving product lifecycle from 0-to-1, especially evident in redesigning Scalicx into a scalable multi-tenant platform and building a centralized lab scheduling system from scratch. He leverages data-driven approaches, including AI agents for prototyping and validation, and has established agile processes to improve development velocity. His experience documenting an undocumented ERP system codebase indicates strong technical communication skills. While there is no explicit mention of RAG (Retrieval-Augmented Generation) systems, his AI product management certification and use of AI tools suggest familiarity with advanced AI concepts. Overall, he meets or exceeds most key and nice-to-have criteria, with minor gaps around explicit RAG system experience.', 'strong_fit', 'Interviewed', NULL, NULL, 'Perfect match as a product manager and a potental CPO \ndid not ask him about his salary though and i remember him living far in haram', 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO "RecruitmentApplication" ("id", "fullName", "email", "role", "referralSource", "linkedin", "portfolio", "aiProject", "additionalInfo", "resumePath", "cloud_storage_path", "isPublic", "createdAt", "aiScore", "aiAnalysis", "recommendation", "interviewStatus", "meetingLink", "adminNotes", "interviewFeedback", "interviewRating") VALUES ('cmj031g360001rr089bpu1z4h', 'Hana Hossam Taha ', 'hanahossam4013@gmail.com', 'executive-assistant', NULL, NULL, NULL, NULL, NULL, ' Hana Hossam Taha CV (final) .pdf', '14890/uploads/1766324315985-Hana_Hossam_Taha_CV.pdf', FALSE, '2025-12-10T14:06:20.850Z', 35, 'The candidate''s background is primarily in sport and exercise psychology, with extensive experience in mental coaching, counseling, and therapeutic roles. There is no indication of executive assistant experience, nor any mention of supporting C-level executives, calendar or meeting management, travel coordination, or handling confidential executive information. While the candidate demonstrates strong communication skills and organizational abilities within their domain, these do not clearly translate to the executive assistant role requirements. There is also no evidence of experience with productivity tools, project coordination, or event planning relevant to an executive assistant position. Overall, the candidate''s profile is specialized in psychology and mental coaching rather than administrative or executive support functions.', 'weak_fit', 'Pending', NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;

